import { Component } from '@angular/core';
import { CsvgeneratorService } from '../csvgenerator.service';
import { Register } from '../interfaces/register';
import Swal from 'sweetalert2';


@Component({
  selector: 'app-new-record',
  templateUrl: './new-record.component.html',
  styleUrls: ['./new-record.component.css'],
})
export class NewRecordComponent {
  concepto: string = '';
  observaciones: string = '';
  cantidad: number = 0;
  tipoOpciones = ['gasto', 'ingreso'];
  tipo: string = '';

  constructor(
    private csvgeneratorService: CsvgeneratorService
  ) {}

  async btnCrear() {
    console.log('Btn crear');
    console.log(this.concepto, this.observaciones, this.cantidad, this.tipo);

    if (this.isValidInput()) {
      //Inputs validos

      try {
        let registro: Register;
        registro = {
          concepto: this.concepto,
          observaciones: this.observaciones,
          cantidad: this.cantidad,
          tipo: this.tipo,
          fecha: new Date
        };
        let success = await this.csvgeneratorService.newRegister(registro);
        console.log(success);
      } catch (error) {
        console.log(error);
      }
    } else {
      //Inputs invalidos
      Swal.fire({
        icon: 'error',
        title: 'Oops...',
        text: 'Valores no validos'    
      })
    }
  }

  isValidInput(): boolean {
    return this.concepto != '' && 
    this.observaciones != ''  && 
    this.tipoOpciones.includes(this.tipo);
  }
}
<h1>Nuevo registro</h1>

<div id="form-nuevo-registro">
    <div>
      <label for="registro-concepto">Concepto</label>
      <input type="text" id="registro-concepto" name="concepto" [(ngModel)]="concepto" required />
    </div>

    <div>
      <label for="registro-observaciones">Observaciones</label>
      <textarea id="registro-observaciones" rows="4" cols="50" name="observaciones" [(ngModel)]="observaciones" required></textarea>
    </div>

    <input type="number" id="registro-cantidad" name="cantidad" min="0" max="1000042" [(ngModel)]="cantidad" required/>

    <fieldset>
      <legend>Tipo</legend>

        <input type="radio" id="rb-gasto" name="tipo" value="gasto" [(ngModel)]="tipo" /> 
        <label for="rb-gasto">Gasto</label>

        <input type="radio" id="rb-ingreso" name="tipo" value="ingreso" [(ngModel)]="tipo" /> 
        <label for="rb-ingreso">Ingreso</label>

    </fieldset>

    <button id="form-crear" type="submit" (click)="btnCrear()">Crear</button>
</div>
